
import {
  defineComponent,
  reactive,
  ref,
  toRaw,
  toRefs,
  watch,
  provide,
} from "vue";
import TableRole from "@/components/tablerole/TableRole.vue";
import { DownloadOutlined } from "@ant-design/icons-vue";

import AddDepartment from "./Department/AddDepartment.vue";
import { deptlist } from "@/server/http/api/role";
// import { DeptExport } from "@/server/DownLoad";
import { useStore } from "vuex";
export default defineComponent({
  name: "Department",

  components: {
    TableRole,
    AddDepartment,
    DownloadOutlined,
  },
  setup() {
    let DepartmentList = ref([]);
    let total = ref(0);

    let Pagination = reactive({
      pageNum: 1,
      pageSize: 10,
    });

    let search = ref("");
    function init() {
      deptlist({
        pageNum: Pagination.pageNum,
        pageSize: Pagination.pageSize,
        search: search.value,
      }).then((res: any) => {
        if (res.data.code === 200) {
          DepartmentList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }

    watch(
      Pagination,
      (newval, o) => {
        deptlist({
          pageNum: Pagination.pageNum,
          pageSize: Pagination.pageSize,
          search: search.value,
        }).then((res: any) => {
          if (res.data.code === 200) {
            DepartmentList.value = res.data.data.list;
            total.value = res.data.data.total;
          }
        });
      },
      {
        immediate: true,
      }
    );
    const onSearch = (searchValue: string) => {
      init();
    };
    let timer: any;
    const onChange = () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        init();
      }, 600);
    };

    provide("initDepartment", init);
    const store = useStore();
    // function download() {
    //   let userInfo: any = JSON.parse(store.state.userInfo.userInfo);

    //   DeptExport(search.value, userInfo.userId);
    // }
    return {
      DepartmentList,
      total,
      Pagination,
      search,
      init,
      // download,
      onChange,
      onSearch,
    };
  },
});
