
import { ref, defineComponent, reactive, inject } from "vue";
import TreeNode from "@/components/tree/TreeNode.vue";
import { deptadd } from "@/server/http/api/role";
export default defineComponent({
  components: {
    TreeNode,
  },
  setup() {
    const formRef = ref();

    const rules = {
      name: [
        { required: true, message: "账号不能为空", trigger: "blur" },
        { min: 1, max: 64, message: "内容在64个字符之内", trigger: "blur" },
      ],

      dev: [
        { required: true, message: "部门不能为空", trigger: "blur" },
        { min: 1, max: 64, message: "内容在64个字符之内", trigger: "blur" },
      ],
      code: [
        { required: true, message: "部门不能为空", trigger: "blur" },
        { min: 1, max: 64, message: "内容在64个字符之内", trigger: "blur" },
      ],
      duty: [
        { required: true, message: "部门不能为空", trigger: "blur" },
        { min: 1, max: 64, message: "内容在64个字符之内", trigger: "blur" },
      ],
    };
    let init: any = inject("initDepartment");
    const formState: any = reactive({
      name: "",
      parentId: 0,
      code: "",
      duty: "",
      dev: "",
    });

    function onDepartmentID(options: any) {
      formState.parentId = options.id;
      formState.dev = options.name;
    }

    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);

    const showModal = () => {
      visible.value = true;
    };

    const handleOk = () => {
      formRef.value
        .validate()
        .then(() => {
          confirmLoading.value = true;
          delete formState.dev;

          deptadd(formState).then((res: any) => {
            //console.log(res);
            if (res.data.code === 200) {
              init();
            }
            visible.value = false;
            confirmLoading.value = false;
            formState.name = "";
            formState.duty = "";
            formState.code = "";
            formState.pid = 0;
            formState.dev = "";
          });
        })
        .catch((error: any) => {
          //console.log("error", error);
        });
    };
    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,
      formState,
      labelCol: { span: 4 },
      wrapperCol: { span: 20 },
      onDepartmentID,
      rules,
      formRef,
    };
  },
});
